    public static server ETG_TransferRegisterTmp insTempTransferOrder(FromDate _fromdate,ToDate _todate,InventTransferId _inventTransferId)
    {
        InventTransferTable             inventTransferTable;
        InventTransferLine              inventTransferLine;
        InventDim                       inventDim, inventDimReceive;
        InventTransferJour              inventTransferJour;
        InventTransferJourLine          inventTransferJourLine;
        ETG_InventTransJourQualitySpec  qualitySpecifications;      
        ETG_TransferBillOfLadingHistory billOfLoadingHistory;
        boolean                         isPartialShip,isPartialReceive;
        int                             i,conCount = 1;
        MarkupTrans                     markuptrans;
        CreatedDateTime                 fromDateTime, toDateTime;
        ETG_TransferRegisterTmp         transferRegisterTmp,transferRegisterShipTmp;       
        container                       shipVoucherCon,receiveVoucherCon;       
        InventOnHand                    inventOnHand;
        InventDimParm                   inventDimParm;

        fromDateTime            = DateTimeUtil::newDateTime(_fromdate,0);
        toDateTime              = DateTimeUtil::newDateTime(_todate,86400);

        while select * from inventTransferTable
            where inventTransferTable.CreatedDateTime >=  fromDateTime
            && inventTransferTable.CreatedDateTime <=  toDateTime
            && (inventTransferTable.TransferId     == _inventTransferId || _inventTransferId == "")
        join inventTransferLine
            where inventTransferLine.TransferId == inventTransferTable.TransferId       
        {
            isPartialReceive  = false;
            isPartialShip     = false;
            conCount          = 1;
            shipVoucherCon    = conNull();
            receiveVoucherCon = conNull();
            transferRegisterTmp.clear();
            transferRegisterTmp.TransferId              = inventTransferTable.TransferId;  
            transferRegisterTmp.TransferStatus          = inventTransferTable.TransferStatus;
            transferRegisterTmp.ItemId                  = inventTransferLine.ItemId;
            transferRegisterTmp.ETG_Advance             = inventTransferTable.ETG_Advance;
            transferRegisterTmp.ETG_VendorName          = inventTransferTable.ETG_VendorName;
            transferRegisterTmp.QtyTransfer             = inventTransferLine.QtyTransfer;
            transferRegisterTmp.UnitPrice               = inventTransferLine.UnitPrice;
            transferRegisterTmp.UnitId                  = inventTransferLine.UnitId;
            transferRegisterTmp.NetAmount               = inventTransferLine.NetAmount;
            transferRegisterTmp.SKU                     = InventTableModule::find(inventTransferLine.ItemId, ModuleInventPurchSales::Invent).UnitId;
            transferRegisterTmp.InventColorId           = inventTransferLine.inventDim().InventColorId;
            transferRegisterTmp.inventDimId             = inventTransferLine.inventDim().inventDimId;
            transferRegisterTmp.BatchNumber             = inventTransferLine.inventDim().inventBatchId;            
            transferRegisterTmp.inventDimId             = inventTransferLine.inventDim().inventDimId;
            transferRegisterTmp.configId                = inventTransferLine.inventDim().configId;
            transferRegisterTmp.InventSizeId            = inventTransferLine.inventDim().InventSizeId;
            transferRegisterTmp.InventColorId           = inventTransferLine.inventDim().InventColorId;
            transferRegisterTmp.InventStyleId           = inventTransferLine.inventDim().InventStyleId;         
            transferRegisterTmp.SupplyingSite           = inventTransferLine.inventDim().InventSiteId;
            transferRegisterTmp.SupplyingWarehouse      = inventTransferLine.inventDim().InventLocationId;
            transferRegisterTmp.wMSLocationId           = inventTransferLine.inventDim().wMSLocationId;
            transferRegisterTmp.InventLocationId        = inventTransferLine.inventDim().InventLocationId;
            transferRegisterTmp.InventSiteId            = inventTransferLine.inventDim().InventSiteId;
            transferRegisterTmp.TransitDays             = inventTransferTable.ReceiveDate - inventTransferTable.ShipDate;           
            transferRegisterTmp.ETG_PackingGroup        = inventTransferLine.ETG_PackingGroup;
            transferRegisterTmp.StockTransferOrderType  = "Transfer Order";
            transferRegisterTmp.StockTransferOrderTypeDescription = "Transfer Order";

            select firstonly Value from markuptrans
                where markuptrans.TransRecId == inventTransferLine.RecId;

            transferRegisterTmp.Value                =  markuptrans.Value;    

            inventDimParm.initFromInventDim(inventTransferLine.inventDim());
            inventOnHand  = InventOnhand::newParameters(inventTransferLine.ItemId, inventTransferLine.inventDim(), inventDimParm);

            transferRegisterTmp.DeliveryPrice = inventOnHand.costPricePcs(false, systemDateGet());
            transferRegisterTmp.UnitPrice     = transferRegisterTmp.DeliveryPrice;

            while select VoucherId,UpdateType,TransDate from inventTransferJour
                order by VoucherId asc
                where inventTransferJour.TransferId == inventTransferTable.TransferId           
            join InventDimId,QtyScrapped,QtyShipped,QtyReceived from inventTransferJourLine
                where inventTransferJourLine.VoucherId == inventTransferJour.VoucherId
            {
                select firstonly TareWeight,NetWeight,GrossWeight,VehicleNumber,VehicleDriver,Transporter from billOfLoadingHistory
                    where billOfLoadingHistory.VoucherId == inventTransferJour.VoucherId;

                inventDim  = InventDim::find(inventTransferJourLine.InventDimId);
                if(inventTransferJour.UpdateType==InventTransferUpdateType::Shipment)
                {
                    if(isPartialShip)
                    {
                        transferRegisterTmp.insert();
                        isPartialReceive  = false;
                        shipVoucherCon    = conIns(shipVoucherCon,conCount,transferRegisterTmp.GoodRecieptNum);
                        receiveVoucherCon = conIns(receiveVoucherCon,conCount,transferRegisterTmp.GoodRecieptNumReceive);
                        conCount++;
                    }
                    transferRegisterTmp.QtyScrapped          = inventTransferJourLine.QtyScrapped;
                    transferRegisterTmp.TareWeight           = billOfLoadingHistory.TareWeight;
                    transferRegisterTmp.NetWeight            = billOfLoadingHistory.NetWeight;
                    transferRegisterTmp.GrossWeight          = billOfLoadingHistory.GrossWeight;
                    transferRegisterTmp.VehicleNumber        = billOfLoadingHistory.VehicleNumber;
                    transferRegisterTmp.VehicleDriver        = billOfLoadingHistory.VehicleDriver;
                    transferRegisterTmp.Transporter          = billOfLoadingHistory.Transporter;
                    transferRegisterTmp.DeliveryQty          = inventTransferJourLine.QtyShipped;
                    transferRegisterTmp.inventBatchId        = inventDim.inventBatchId;
                    transferRegisterTmp.GoodRecieptNum       = inventTransferJour.VoucherId;
                    transferRegisterTmp.SupplyingLocationId  = inventDim.wMSLocationId;
                    transferRegisterTmp.VoucherId            = inventTransferJour.VoucherId;
                    transferRegisterTmp.TransDate            = inventTransferJour.TransDate;
                    transferRegisterTmp.NetAmount            = transferRegisterTmp.DeliveryQty * transferRegisterTmp.DeliveryPrice;

                    i = 1;
                    while select SubGroupDescription,ResultValue from qualitySpecifications
                        where qualitySpecifications.VoucherId == inventTransferJour.VoucherId
                    {                        
                        if(i < 12)
                        {
                            transferRegisterTmp.SpecificationGroupDsc[i] = qualitySpecifications.SubGroupDescription;
                            transferRegisterTmp.ShipResultValue[i]       = qualitySpecifications.ResultValue;
                        }

                        i++;
                    }
                    transferRegisterTmp.SpecCount = i;                   

                    isPartialShip = true;
                }

                else if(inventTransferJour.UpdateType==InventTransferUpdateType::Receive)
                {
                    if(isPartialReceive)
                    {  
                        if(conFind(shipVoucherCon,transferRegisterTmp.GoodRecieptNum))
                        {
                            transferRegisterTmp = ETG_TransferRegisterEngine::clearShipDetails(transferRegisterTmp);
                        }
                        transferRegisterTmp.insert(); 

                        shipVoucherCon    = conIns(shipVoucherCon,conCount,transferRegisterTmp.GoodRecieptNum);
                        receiveVoucherCon = conIns(receiveVoucherCon,conCount,transferRegisterTmp.GoodRecieptNumReceive);
                        conCount++;
                    }
                    transferRegisterTmp.ReceivingTareWeight      = billOfLoadingHistory.TareWeight;
                    transferRegisterTmp.ReceivingNetWeight       = billOfLoadingHistory.NetWeight;
                    transferRegisterTmp.ReceivingGrossWeight     = billOfLoadingHistory.GrossWeight;
                    transferRegisterTmp.ReceiveVehicleNumber     = billOfLoadingHistory.VehicleNumber;
                    transferRegisterTmp.ReceiveVehicleDriver     = billOfLoadingHistory.VehicleDriver;
                    transferRegisterTmp.ReceiveTransporter       = billOfLoadingHistory.Transporter;
                    transferRegisterTmp.GoodRecieptNumReceive    = inventTransferJour.VoucherId;
                    transferRegisterTmp.TransDateReceive         = inventTransferJour.TransDate;
                    transferRegisterTmp.QtyReceived              = inventTransferJourLine.QtyReceived;
                    transferRegisterTmp.ReceivingSite            = inventDim.InventSiteId;
                    transferRegisterTmp.ReceivingWarehouse       = inventDim.InventLocationId;
                    transferRegisterTmp.ReceivingLocationId      = inventDim.wMSLocationId;
                    transferRegisterTmp.inventBatchIdReceive     = inventDim.inventBatchId;
                    transferRegisterTmp.DeliveryValue            = transferRegisterTmp.QtyReceived * transferRegisterTmp.DeliveryPrice;

                    i = 1;
                    while select ResultValue from qualitySpecifications
                        where qualitySpecifications.VoucherId == inventTransferJour.VoucherId
                    {
                        if(i < 12)
                        {
                            transferRegisterTmp.ReceiveResultValue[i]  = qualitySpecifications.ResultValue;
                            transferRegisterTmp.DiffResultValue[i]     = transferRegisterTmp.ShipResultValue[i] - qualitySpecifications.ResultValue;                        
                        }

                        i++;
                    }   


                    isPartialReceive = true;
                }               
            }  

            if(conFind(shipVoucherCon,transferRegisterTmp.GoodRecieptNum))
            {
                transferRegisterTmp = ETG_TransferRegisterEngine::clearShipDetails(transferRegisterTmp);
            }
            transferRegisterTmp.insert();
        }

        return transferRegisterTmp;
    }

public static ETG_TransferRegisterTmp clearShipDetails(ETG_TransferRegisterTmp  _transferRegisterTmp)
{
    ETG_TransferRegisterTmp     transferRegisterTmp;

    transferRegisterTmp = _transferRegisterTmp;

    transferRegisterTmp.QtyScrapped          = 0;
    transferRegisterTmp.TareWeight           = 0;
    transferRegisterTmp.NetWeight            = 0;
    transferRegisterTmp.GrossWeight          = 0;
    transferRegisterTmp.VehicleNumber        = '';
    transferRegisterTmp.VehicleDriver        = '';
    transferRegisterTmp.Transporter          = '';
    transferRegisterTmp.DeliveryQty          = 0;
    transferRegisterTmp.inventBatchId        = '';
    transferRegisterTmp.GoodRecieptNum       = '';
    transferRegisterTmp.SupplyingLocationId  = '';
    transferRegisterTmp.VoucherId            = '';
    transferRegisterTmp.TransDate            = dateNull();
    transferRegisterTmp.NetAmount            = 0;

    return transferRegisterTmp;
}

